class Solution {
public:
    int findNumberOfLIS(vector<int>& nums) {
        vector<int>dp(nums.size()+1,1);
        vector<int>g(nums.size()+1,1);
        //边界啊啊啊啊
        int ans=1;
        for(int i=1;i<nums.size();i++)
        {
            for(int j=i-1;j>=0;j--)
            {
                if(nums[j]<nums[i])
                {
                    if(dp[i]<dp[j]+1)
                    {
                        dp[i]=max(dp[i],dp[j]+1);
                        g[i]=g[j];
                    }
                    else if(dp[i]==dp[j]+1)
                    {
                        g[i]+=g[j];
                    } 
                }


                // cout<<dp[i]<<" ";
            }
            // cout<<dp[i]<<" ";
            ans=max(dp[i],ans);
        }
        int res=0;
        for(int i=0;i<nums.size();i++)
        {
            if(dp[i]==ans)
            {
                res+=g[i];
            }
        }
        return res;
    }
};
